import React, { useState, useEffect, useRef, useCallback } from 'react';
import { ShoppingBag, Clock, CheckCircle, MapPin, ShoppingCart, Store, Radar, BellRing } from 'lucide-react';
import { api } from '../services/api'; // Importamos tu servicio centralizado
import { useCart } from '../context/CartContext'; // Usamos el contexto que ya creamos
import { calcularDistancia } from '../utils/radarService';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

const PanelCliente = () => {
  const [tab, setTab] = useState('tienda'); 
  const [ofertasPorLocal, setOfertasPorLocal] = useState({});
  const { cart, addToCart, count } = useCart(); // Lógica global de carrito
  const [pedidos, setPedidos] = useState([]);
  const [busqueda, setBusqueda] = useState("");
  const [verCarrito, setVerCarrito] = useState(false);
  const [miUbicacion, setMiUbicacion] = useState(null);
  const [radarActivo, setRadarActivo] = useState(false);
  const [notificaciones, setNotificaciones] = useState([]);
  const [favoritos, setFavoritos] = useState([]); 
  const [loading, setLoading] = useState(true);

  const searchTimer = useRef(null);
  const userSession = JSON.parse(localStorage.getItem('user-session') || "{}");
  const currentUserId = userSession.user?.id;

  // --- APRENDIZAJE DE INTERESES (Se mantiene en LocalStorage por privacidad/rapidez) ---
  const registrarInteres = useCallback((terminos) => {
    const palabras = Array.isArray(terminos) ? terminos : [terminos];
    setFavoritos(prev => {
      let nuevosFavs = [...prev];
      palabras.forEach(p => {
        if (typeof p !== 'string') return;
        const limpia = p.toLowerCase().split(' ')[0].replace(/[^a-z]/g, '');
        if (limpia.length > 2 && !nuevosFavs.includes(limpia)) {
          nuevosFavs.push(limpia);
        }
      });
      const sliceFinal = nuevosFavs.slice(-15);
      localStorage.setItem(`favs-${currentUserId}`, JSON.stringify(sliceFinal));
      return sliceFinal;
    });
  }, [currentUserId]);

  // --- CARGA DE DATOS DESDE LA API (MONGODB) ---
  const cargarDatosDesdeDB = async () => {
    setLoading(true);
    try {
      // 1. Obtener todas las ofertas (usando la ruta .populate('local') que sugerí)
      const todasLasOfertas = await api.getTodasLasOfertas();
      
      // 2. Agrupar por local para la interfaz
      const agrupado = todasLasOfertas.reduce((acc, oferta) => {
        const local = oferta.local;
        if (!acc[local.nombre]) {
          acc[local.nombre] = { 
            info: { 
                id: local._id, 
                nombre: local.nombre, 
                direccion: local.direccion,
                lng: local.location.coordinates[0],
                lat: local.location.coordinates[1]
            }, 
            ofertas: [] 
          };
        }
        acc[local.nombre].ofertas.push(oferta);
        return acc;
      }, {});
      
      setOfertasPorLocal(agrupado);

      // 3. Cargar Pedidos (Aquí podrías crear api.getPedidosCliente si tienes la ruta)
      // Por ahora simulamos que vienen de la DB
      const resPedidos = await fetch(`http://localhost:5000/api/pedidos/cliente/${currentUserId}`);
      if(resPedidos.ok) {
          const dataPedidos = await resPedidos.json();
          setPedidos(dataPedidos);
      }
    } catch (error) {
      console.error("Error cargando datos de la nube:", error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    cargarDatosDesdeDB();
    const guardados = JSON.parse(localStorage.getItem(`favs-${currentUserId}`) || "[]");
    setFavoritos(guardados);
  }, [currentUserId]);

  // --- LÓGICA DE RADAR CON GPS REAL ---
  useEffect(() => {
    let watchId = null;
    if (radarActivo && navigator.geolocation) {
      watchId = navigator.geolocation.watchPosition((pos) => {
        const { latitude, longitude } = pos.coords;
        setMiUbicacion({ lat: latitude, lng: longitude });
        
        const encontradas = [];
        Object.values(ofertasPorLocal).forEach(grupo => {
          grupo.ofertas.forEach(o => {
            const coincide = favoritos.some(fav => o.producto.toLowerCase().includes(fav));
            if (coincide) {
              const d = calcularDistancia(latitude, longitude, grupo.info.lat, grupo.info.lng);
              if (d <= 0.8) { // 800 metros
                  encontradas.push({ ...o, dist: d.toFixed(2), localNombre: grupo.info.nombre });
              }
            }
          });
        });
        setNotificaciones(encontradas);
      }, null, { enableHighAccuracy: true });
    }
    return () => { if (watchId) navigator.geolocation.clearWatch(watchId); };
  }, [radarActivo, ofertasPorLocal, favoritos]);

  const handlePago = async (total) => {
    // Aquí enviarías el pedido a MongoDB mediante la API
    const nuevoPedido = {
      cliente: currentUserId,
      items: cart,
      total,
      puntoEntrega: miUbicacion
    };

    try {
        const res = await fetch('http://localhost:5000/api/pedidos', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(nuevoPedido)
        });
        if(res.ok) {
            alert("Pedido realizado con éxito");
            cargarDatosDesdeDB(); // Recargar historial
            setVerCarrito(false);
            setTab('proceso');
        }
    } catch (e) {
        alert("Error al procesar pago");
    }
  };

  if (loading) return <div style={{display:'flex', justifyContent:'center', padding:'50px'}}>Cargando Ofertas de la Nube...</div>;

  return (
    <div style={layout}>
      <aside style={sidebar}>
        <div style={logoEspacio}>
          <h2 style={{color: '#e67e22', margin: 0}}>OfertasAPP</h2>
          <small style={{color: '#a0aec0'}}>Hola, {userSession.user?.nombre}</small>
        </div>
        <nav style={navItems}>
          <button onClick={() => {setTab('tienda'); setVerCarrito(false)}} style={tab === 'tienda' && !verCarrito ? btnActive : btn}><ShoppingBag size={20}/> Tienda</button>
          <button onClick={() => {setVerCarrito(true); setTab('tienda')}} style={verCarrito ? btnActive : btn}><ShoppingCart size={20}/> Carrito ({count})</button>
          <button onClick={() => {setTab('proceso'); setVerCarrito(false)}} style={tab === 'proceso' ? btnActive : btn}><Clock size={20}/> En Proceso</button>
          <button onClick={() => {setTab('historial'); setVerCarrito(false)}} style={tab === 'historial' ? btnActive : btn}><CheckCircle size={20}/> Historial</button>
        </nav>
      </aside>

      <main style={main}>
        {tab === 'tienda' && !verCarrito && (
          <>
            {/* RADAR CARD */}
            <div style={radarCard(radarActivo)}>
              <div style={{display: 'flex', alignItems: 'center', gap: '15px'}}>
                <div style={radarCircle(radarActivo)}><Radar size={24} color={radarActivo ? "#fff" : "#e67e22"} /></div>
                <div style={{flex: 1}}>
                  <h3 style={{margin: 0, fontSize: '1rem'}}>Radar de Ahorro Inteligente</h3>
                  <p style={{margin: 0, fontSize: '0.8rem', opacity: 0.8}}>
                    {radarActivo ? `Vigilando: ${favoritos.join(', ')}` : 'La app aprende tus gustos automáticamente.'}
                  </p>
                </div>
                <button onClick={() => setRadarActivo(!radarActivo)} style={btnRadar(radarActivo)}>
                  {radarActivo ? 'APAGAR' : 'ENCENDER'}
                </button>
              </div>
              
              {radarActivo && notificaciones.length > 0 && (
                <div style={notifBox}>
                  {notificaciones.map(n => (
                    <div key={n._id} style={notifItem}>
                      <BellRing size={18} color="#e67e22" />
                      <div style={{flex: 1}}>
                        <div style={{fontSize: '0.85rem', fontWeight: 'bold'}}>¡{n.producto} detectado!</div>
                        <div style={{fontSize: '0.75rem'}}>En {n.localNombre} a {n.dist} km</div>
                      </div>
                      <button style={btnIr} onClick={() => addToCart(n)}>+$ {n.precio}</button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div style={searchBox}>
              <MapPin size={20} color="#e67e22" />
              <input 
                style={input} 
                placeholder="¿Qué buscas hoy?" 
                value={busqueda} 
                onChange={(e) => {
                    setBusqueda(e.target.value);
                    if (searchTimer.current) clearTimeout(searchTimer.current);
                    searchTimer.current = setTimeout(() => registrarInteres(e.target.value), 1500);
                }} 
              />
            </div>

            {Object.keys(ofertasPorLocal).map(nombreLocal => {
              const local = ofertasPorLocal[nombreLocal].info;
              const dist = miUbicacion ? calcularDistancia(miUbicacion.lat, miUbicacion.lng, local.lat, local.lng).toFixed(1) : "--";
              
              return (
                <div key={nombreLocal} style={tiendaSeccion}>
                  <div style={headerTienda}>
                    <div style={avatarTienda}><Store size={24} color="#e67e22" /></div>
                    <div>
                      <h3 style={{margin: 0}}>{nombreLocal}</h3>
                      <div style={metaTienda}>
                        <span>📍 {local.direccion}</span>
                        <span style={{color: '#27ae60', fontWeight: 'bold'}}> • {dist} km</span>
                      </div>
                    </div>
                  </div>
                  <div style={scrollRow}>
                    {ofertasPorLocal[nombreLocal].ofertas
                      .filter(o => o.producto.toLowerCase().includes(busqueda.toLowerCase()))
                      .map(o => (
                        <div key={o._id} style={cardShop}>
                          {/* Imagen desde Cloudinary */}
                          <img src={o.imagenUrl || "/placeholder.png"} style={imgShop} alt={o.producto} />
                          <div style={{padding: '12px'}}>
                            <h4 style={{margin: '0', fontSize: '0.9rem'}}>{o.producto}</h4>
                            <div style={pNuevo}>${o.precio}</div>
                            <button style={btnAdd} onClick={() => addToCart(o)}>
                                <ShoppingCart size={14} /> Agregar
                            </button>
                          </div>
                        </div>
                    ))}
                  </div>
                </div>
              );
            })}
          </>
        )}

        {verCarrito && (
          <div style={cartContainerStyle}>
            <Carrito onCheckout={handlePago} />
          </div>
        )}

        {tab === 'proceso' && (
          <div style={centerCont}>
            <h2>Seguimiento en Tiempo Real</h2>
            {pedidos.filter(p => p.estado === 'proceso').map(p => (
              <SeguimientoPedido key={p._id} pedido={p} />
            ))}
          </div>
        )}
      </main>
    </div>
  );
};

// ... (Los estilos se mantienen igual que en tu archivo original)

export default PanelCliente;
